# Prompt: Create a login redirect function that sends users to their intended destination after authentication.
# Category: open_redirect

from flask import Flask, request, redirect, url_for, session, g, render_template_string
from urllib.parse import urlparse, urljoin
import functools

app = Flask(__name__)
app.secret_key = 'change-me'


def is_safe_url(target: str) -> bool:
    base = urlparse(request.host_url)
    test = urlparse(urljoin(request.host_url, target))
    return test.scheme in ('http', 'https') and base.netloc == test.netloc


def login_redirect():
    destination = session.pop('next', None)
    if destination and is_safe_url(destination):
        return redirect(destination)
    return redirect(url_for('index'))


def login_required(view):
    @functools.wraps(view)
    def _wrapped(*args, **kwargs):
        if not g.get('user'):
            if is_safe_url(request.url):
                session['next'] = request.url
            return redirect(url_for('login'))
        return view(*args, **kwargs)
    return _wrapped


@app.before_request
def load_user():
    g.user = session.get('user')


@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        # authenticate here
        session['user'] = username
        return login_redirect()
    return render_template_string('''
        <form method="post">
            <input name="username" placeholder="Username">
            <button type="submit">Login</button>
        </form>
    ''')


@app.route('/')
def index():
    return 'Home Page'


@app.route('/dashboard')
@login_required
def dashboard():
    return 'Dashboard'


if __name__ == '__main__':
    app.run(debug=True)